# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

using System;
using System.Threading;
using Microsoft.EntityFrameworkCore;

public class TicketBookerService
{
    private readonly EventContext _context;

    public TicketBookerService(EventContext context)
    {
        _context = context;
    }

    public async Task<bool> BookTicketsAsync(int eventId, int quantity, CancellationToken cancellationToken)
    {
        var @event = await _context.Events.FindAsync(eventId);
        if (@event == null)
        {
            throw new Exception("Invalid event ID");
        }

        // Check available seats
        if (quantity > @event.AvailableSeats)
        {
            return false;
        }

        // Validate purchase quantity
        var minPurchaseQuantity = 10;
        if (quantity < minPurchaseQuantity)
        {
            return false;
        }

        // Update inventory
        @event.AvailableSeats -= quantity;
        await _context.SaveChangesAsync(cancellationToken);

        return true;
    }
}